        length = data[1] & 127
        if length == 126:
            length = struct.unpack('>H', data[2:4])[0]
        elif length == 127:
            length = struct.unpack('>Q', data[2:10])[0]
        
        message = data[2 + (4 if length == 126 else 10):]
        message = message[:length].decode('utf-8')
        return message

